import{_ as e,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"57A. Designated Location Bonus","description":"","frontmatter":{"title":"57A. Designated Location Bonus","eba":"Doctors in Training 2022-2026","topics":["allowances"]},"headers":[],"relativePath":"ebas/doctors-in-training/allowances/57A-designated-location-bonus.md","filePath":"ebas/doctors-in-training/allowances/57A-designated-location-bonus.md"}'),s={name:"ebas/doctors-in-training/allowances/57A-designated-location-bonus.md"};function i(r,t,p,l,g,c){return o(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="_57a-designated-location-bonus" tabindex="-1">57A. Designated Location Bonus <a class="header-anchor" href="#_57a-designated-location-bonus" aria-label="Permalink to &quot;57A. Designated Location Bonus&quot;">​</a></h1><p><strong>57A.1</strong> Application</p><p><strong>(a)</strong> The purpose of the Designated Location Bonus is to support the recruitment and retention of Doctors employed in Designated Locations in rural and regional Victoria.</p><p><strong>(b)</strong> A Designated Location Bonus is payable to a Doctor employed at a Designated Location, subject to the conditions and eligibility terms set out in this clause after the completion of each Eligible Year of Employment.</p><p><strong>(c)</strong> In this clause 57A:</p><p><strong>(i)</strong> Designated Location means the Employers listed in 57A.4 of this clause</p><p><strong>(ii)</strong> ‘employed at a Designated Location’ means employed at that Designated Location listed at xx.4 by the Employer who is either named as the Designated Location or who operates the Designated Location.</p><p><strong>(iii)</strong> Eligible Year of Employment means the twelve month period between anniversary dates of commencement at the Designated Location.</p><p><strong>57A.2</strong> Eligibility</p><p><strong>(a)</strong> Subject to the conditions and eligibility terms set out in this clause, a Doctor employed at a Designated Location will receive the Designated Location Bonus after the completion of an Eligible Year of Employment, pro-rata (1/38th) for part- time, not payable to casuals.</p><p><strong>(b)</strong> The Designated Location Bonus:</p><p><strong>(i)</strong> is not payable where the Doctor is already in receipt of an increased or accelerated base rate of pay, and/or is in receipt of a ‘top-up’ payment, specifically set to attract/retain the Doctor to/at their location;</p><p><strong>(ii)</strong> will be subject to offset/absorption, either in full or part, where the Doctor is in receipt of remuneration in excess of the minimum prescribed under this Agreement; and</p><p><strong>(iii)</strong> is not payable where a Doctor’s engagement at a Designated Location is because of a Rotation (regardless of how the rotation is structured in terms of the employing entity) or other short-term arrangement.</p><p>Example:</p><p>A Doctor is rotated to a Designated Location from 1 March 2023 until 1 March 2024.</p><p>As the Doctor’s engagement at a Designated Location was because of a Rotation (regardless of how the rotation is structured in terms of the employing entity) they are not eligible for any payment.</p><p><strong>57A.3</strong> Quantum of Bonus</p><p>The Designated Location Bonus is as follows:</p><p>Date Designated Location Bonus</p><p>1 July 2023 – 30 June 2024 $5,000</p><p>1 July 2024 - 30 June 2025 $6,000</p><p>1 July 2025 – 30 June 2026 $7,000</p><p>Example:</p><p>A Doctor is employed at a Designated Location from 1 March 2023 and is still employed at the Designated Location on 1 March 2024, that period is the Eligible Year of Employment. The Doctor is paid per the wage schedule in the Agreement.</p><p>As the end of their Eligible Year of Employment is within the 1 July 2023 – 30 June 2024 period, they are entitled to a $5,000 Designated Location Bonus.</p><p><strong>57A.4</strong> Designated Locations</p><p>The Designated Locations are as follows:</p><p><strong>(a)</strong> Albury Wodonga Health (Wodonga Hospital only)</p><p><strong>(b)</strong> Bairnsdale Regional Health Service;</p><p><strong>(c)</strong> Central Gippsland Health Service;</p><p><strong>(d)</strong> Echuca Regional Health;</p><p><strong>(e)</strong> Gippsland Southern Health Service;</p><p><strong>(f)</strong> Goulburn Valley Health</p><p><strong>(g)</strong> Horsham Hospital;</p><p><strong>(h)</strong> Mildura Base Public Hospital;</p><p><strong>(i)</strong> Portland Base Public Hospital;</p><p><strong>(j)</strong> South West Healthcare;</p><p><strong>(k)</strong> Swan Hill District Health;</p><p><strong>(l)</strong> Western District Health Service;</p><p><strong>(m)</strong> Bacchus Marsh Hospital;</p><p><strong>(n)</strong> Bass Coast Health;</p><p><strong>(o)</strong> North East Health Wangaratta; and</p><p><strong>(p)</strong> West Gippsland Healthcare Group</p><p>Plain language terms: location bonus, rural bonus.</p>',45)])])}const u=e(s,[["render",i]]);export{h as __pageData,u as default};
